import axios from 'axios';

const FILE_ID = 'NBHU5lsSfPTBMnlFVPxHNB'; // Your Figma file ID
const FIGMA_TOKEN = 'figd_9IgwTEDRk2P6kWhTjRvtOmkFcAKniW9pPya9ohwA'; // Your Figma personal access token
const BUTTON_NODE_ID = '1-1334'; // The Node ID for the button component

/**
 * Fetch data for a specific node (button) in the Figma file
 * @returns {Promise<Object>} - Raw button data from Figma API
 */
export const fetchButtonData = async () => {
    try {
        const response = await axios.get(
            `https://api.figma.com/v1/files/${FILE_ID}/nodes?ids=${BUTTON_NODE_ID}`,
            {
                headers: { 'X-Figma-Token': FIGMA_TOKEN },
            }
        );

        // Check if the data for the specified node ID is available
        const rawData = response.data.nodes[BUTTON_NODE_ID]?.document;
        if (!rawData) {
            throw new Error('No data found for the specified node ID');
        }

        return rawData; // Return raw data if formatting is done elsewhere
    } catch (error) {
        console.error('Error fetching button data from Figma:', error);
        throw error;
    }
};

/**
 * Format the button data to include only relevant properties
 * @param {Object} data - Raw data from Figma API
 * @returns {Object} - Simplified button data with essential properties
 */
export const formatButtonData = (data) => ({
    name: data.name,
    type: data.type,
    color: data.fills?.[0]?.color,
    width: data.absoluteBoundingBox?.width,
    height: data.absoluteBoundingBox?.height,
});
